    def perform_test(self):

        config = {
            "n_ul_rb": 100,
            "n_ra_prb_offset": 90,
            "phi": 7,
            "delta_f_ra": 1250,
            "delta_f": 15000
        }

        block = SubcarrierDemappingBlock(config)

        data = CommonDataEx()

        data.meta = {
            "fft": self.input_data,
            "n_ul_rb": config["n_ul_rb"],
            "n_ra_prb_offset": config["n_ra_prb_offset"]
        }

        block.process(data)

        python_output = np.array(
            data.meta.get("Subcarrier_Demapping", []),
            dtype=complex
        )
        print("PYTHON:")
        print(python_output[:10])

        print("\nREFERENCE:")
        print(self.reference_output[:10])

        tolerance = 1e-7

        error_vector = np.abs(
            python_output - self.reference_output
        )

        max_error = np.max(error_vector)

        mismatch_count = np.sum(
            error_vector > tolerance
        )

        print(f"MAX ERROR: {max_error}")
        print(f"MISMATCH COUNT: {mismatch_count}")

        self.assertTrue(
            np.allclose(
                python_output,
                self.reference_output,
                atol=tolerance
            ),
            "Subcarrier Demapping differs from MATLAB reference"
        )

    def test_demapping(self):

        self.perform_test()


